class Solution(object):
    def rowAndMaximumOnes(self, mat):
        best_row = 0
        best_count = 0
        for i, row in enumerate(mat):
            c = sum(row)
            if c > best_count:
                best_count = c
                best_row = i
        return [best_row, best_count]
